=This is the employee time report for the period from from {{ $json.firstDay }} to {{ $json.lastDay }}
The expected tracked time in this period is {{ $json.expectedHours }} hours.
Tolerance is ±0.5h.

Employees who have tracked within those limits:
{{ $json.inRange || "None" }}

Employees who have not tracked within those limits:
{{ $json.outOfRange }}

parameters.jsCode:
const items = $input.all();
const startDate = new Date(items[0]?.json["firstDay"]);
const endDate = new Date(items[0]?.json["lastDay"]);
const dateChunks = [];

while (startDate < endDate) {
  const chunkEnd = new Date(startDate);
  chunkEnd.setDate(chunkEnd.getDate() + 4);
  if (chunkEnd > endDate) {
    chunkEnd.setDate(endDate.getDate());
  }

  dateChunks.push({
    start: startDate.toISOString().split("T")[0],
    end: chunkEnd.toISOString().split("T")[0],
  });

  startDate.setDate(startDate.getDate() + 5);
}

return dateChunks.map((chunk, index) => ({ json: chunk, pairedItem: index }));

const items = $input.all();
const results = items.map((item) => {
  const currentDate = new Date(item.json.currentDate);
  const previousMonthLastDay = new Date(
    currentDate.getFullYear(),
    currentDate.getMonth(),
    0,
  );
  const previousMonthFirstDay = new Date(
    currentDate.getFullYear(),
    currentDate.getMonth() - 1,
    1,
  );
  return {
    json: {
      firstDay: previousMonthFirstDay.toISOString().split("T")[0],
      lastDay: previousMonthLastDay.toISOString().split("T")[0],
    },
  };
});
return results;

// n8n Function node code
// Output: { expectedHours, inRange: [...], outOfRange: [...] }
// Working days = Monday–Friday, inclusive

function parseISOToUTCDate(iso) {
  const [y, m, d] = iso.split("-").map(Number);
  return new Date(Date.UTC(y, m - 1, d));
}

function countWorkingDaysInclusive(firstDay, lastDay) {
  let start = parseISOToUTCDate(firstDay);
  const end = parseISOToUTCDate(lastDay);

  let workingDays = 0;
  for (let t = start.getTime(), e = end.getTime(); t <= e; t += 86400000) {
    const day = new Date(t).getUTCDay(); // 0=Sun, 6=Sat
    if (day >= 1 && day <= 5) workingDays++; // Mon–Fri
  }
  return workingDays;
}

function round2(n) {
  return Math.round((n + Number.EPSILON) * 100) / 100;
}

const TOLERANCE = 0.5;

// n8n input
const { data = [], firstDay, lastDay } = items[0].json;

const expectedHours = round2(countWorkingDaysInclusive(firstDay, lastDay) * 8);

const inRange = [];
const outOfRange = [];

for (let i = 0; i < data.length; i++) {
  const tracked = Number(data[i].sum_trackedTime) || 0;
  const entry = {
    userName: data[i].userName,
    sum_trackedTime: round2(tracked),
  };

  if (Math.abs(tracked - expectedHours) <= TOLERANCE) {
    inRange.push(entry);
  } else {
    outOfRange.push(entry);
  }
}

return [
  {
    json: {
      expectedHours,
      inRange,
      outOfRange,
    },
  },
];

// n8n Function node code
// Converts inRange / outOfRange arrays into Markdown-formatted lists
// If an array is empty, returns "List is empty"

function round2(n) {
  return Math.round((n + Number.EPSILON) * 100) / 100;
}

function toMarkdownList(arr) {
  if (!arr || arr.length === 0) return "List is empty";

  return arr
    .map((u) => `- ${u.userName} (${round2(u.sum_trackedTime)}h)`)
    .join("\n");
}

// n8n input
const { expectedHours, inRange = [], outOfRange = [] } = items[0].json;

return [
  {
    json: {
      expectedHours,
      inRange: toMarkdownList(inRange),
      outOfRange: toMarkdownList(outOfRange),
    },
  },
];
